	.TITLE	ALARME;	--------------------------------------;		(C) 1986 - Daniel Roux;	--------------------------------------;	Source pour EPROM 2732 du processeur HD63P01	.PROC	M6801		; mmes instructions que le M6800; Constantes; ----------REG	=	H'0000		; registres internesRAM	=	H'0080		; dbut de la RAM interneLRAM	=	H'0080		; lg de la RAM interneROM	=	H'F000		; dbut de l'EPROM 2732LROM	=	H'1000		; lg de l'EPROM 2732; Notes; -----DO	=	100RE	=	89MI	=	79FA	=	75SOL	=	67LA	=	59SI	=	53DO1	=	50; Touches du clavier; ------------------ENTER	=	H'0DCLEAR	=	H'7FF1	=	'AF2	=	'BF3	=	'C; Internal register area; ----------------------	.LOC	REGDDIR1:	.BLKB	1		; port1: directionDDIR2:	.BLKB	1		; port2: directionDATA1:	.BLKB	1		; port1: dataDATA2:	.BLKB	1		; port2: dataDDIR3:	.BLKB	1		; port3: directionDDIR4:	.BLKB	1		; port4: directionDATA3:	.BLKB	1		; port3: dataDATA4:	.BLKB	1		; port4: dataTIMER:	.BLKB	1		; timer: control and statusCOUNTH:	.BLKB	1		; counter (high)COUNTL:	.BLKB	1		; counter (low)COMPH:	.BLKB	1		; compare (high)COMPL:	.BLKB	1		; compare (low)CAPTH:	.BLKB	1		; capture (high)CAPTL:	.BLKB	1		; capture (low)CTRL3:	.BLKB	1		; port3: controlRATE:	.BLKB	1		; rate and modeTRSTA:	.BLKB	1		; transmit/receive statusRDATA:	.BLKB	1		; receive: dataTDATA:	.BLKB	1		; transmit: dataRAMCR:	.BLKB	1		; RAM control; Variables; ---------LBUTEL	=	8LBUDEL	=	3	.LOC	RAMCPOS:	.BLKB	1		; position du curseur (0..15)SAVPOS:	.BLKB	1		; GETLINE: position du curseurSAVLGB:	.BLKB	1		; GETLINE: lg bufferSAVPTB:	.BLKB	2		; GETLINE: ^bufferFONC:	.BLKB	1		; touche fonction (F1, F2 ou F3)RANG:	.BLKB	1		; rang dans touche fonctionRANGS:	.BLKB	1		; rang suivantBUTEL:	.BLKB	LBUTEL+1	; numro de tlphoneBUDEL1:	.BLKB	LBUDEL+1	; dlai 1BUDEL2:	.BLKB	LBUDEL+1	; dlai 2BUDEL3:	.BLKB	LBUDEL+1	; dlai 3CODE:	.BLKB	1		; 1 => appel cod (2x)COUNT0:	.BLKB	2		; SONNE?: compteur mono-stableCOUNT1:	.BLKB	2		; SONNE?: compteur dure des 1MARQUE:	.BLKB	1		; marqueur de surveillanceNBRAP:	.BLKB	1		; nb d'appels reusNBEAP:	.BLKB	1		; nb d'appels reus sans codeNBSAP:	.BLKB	1		; nb d'appels envoysNOTE:	.BLKB	1		; BIP: valeur de la note; Dbut de l'EPROM 2732; ---------------------	.LOC	ROMSTART:	LOAD	SP,#RAM+LRAM-1	LOAD	IX,#TAINIT	CALL	INIPER	LOAD	A,#0	LOAD	BUTEL,A;;?	LOAD	BUDEL1,A;;?	LOAD	BUDEL2,A	LOAD	BUDEL3,A	LOAD	CODE,A	LOAD	NBRAP,A	LOAD	NBEAP,A	LOAD	NBSAP,A	LOAD	A,#'6	LOAD	BUDEL1+0,A	LOAD	A,#'0	LOAD	BUDEL1+1,A	; BUDEL1 <-- "60"	LOAD	A,#0	LOAD	BUDEL1+2,A	LOAD	A,#'4	LOAD	BUDEL2+0,A	; BUDEL2 <-- "4"	LOAD	A,#0	LOAD	BUDEL2+1,A	CALL	LCDINIT	LOAD	A,#F1	LOAD	FONC,ALOOP0:	LOAD	A,#0	LOAD	RANG,ALOOP:	CALL	AFEOP	LOAD	A,FONC	COMP	A,#F3	JUMP,EQ 30$	LOAD	A,FONC	COMP	A,#F2	JUMP,NE DOF120$:                	JUMP	DOF230$:	JUMP	DOF3DOF1:	LOAD	A,RANG	COMP	A,#1	JUMP,EQ	DOF1B	COMP	A,#2	JUMP,EQ	DOF1CDOF1A:	LOAD	A,#1	LOAD	RANGS,A	LOAD	IX,#TXTEL	CALL	AFTEXT	LOAD	IX,#BUTEL	LOAD	B,#LBUTEL	JUMP	DOFDOF1B:	LOAD	A,#2	LOAD	RANGS,A	LOAD	IX,#TXCOD0	LOAD	A,CODE	JUMP,EQ 10$	LOAD	IX,#TXCOD110$:	CALL	AFTEXT20$:	CALL	GETCAR		; attend une touche ...	COMP	A,#F1	JUMP,EQ	50$	COMP	A,#F2	JUMP,EQ	50$	COMP	A,#F3	JUMP,EQ	50$	COMP	A,#ENTER	JUMP,EQ	50$	COMP	A,#'0	JUMP,EQ 30$	COMP	A,#'1	JUMP,EQ 30$	COMP	A,#'2	JUMP,NE 20$30$:	SUB	A,#'0		; A <-- 0/1/2	LOAD	CODE,A	JUMP	LOOP50$:	JUMP	DOFF                    DOF1C:	LOAD	A,#0	LOAD	RANGS,A	LOAD	IX,#TXDEL1	CALL	AFTEXT	LOAD	IX,#BUDEL1	LOAD	B,#LBUDEL	JUMP	DOFDOF2:	LOAD	A,RANG	COMP	A,#1	JUMP,EQ	DOF2BDOF2A:	LOAD	A,#1	LOAD	RANGS,A	LOAD	IX,#TXDEL2	CALL	AFTEXT	LOAD	IX,#BUDEL2	LOAD	B,#LBUDEL	JUMP	DOFDOF2B:	LOAD	A,#0	LOAD	RANGS,A	LOAD	IX,#TXDEL3	CALL	AFTEXT	LOAD	IX,#BUDEL3	LOAD	B,#LBUDEL	JUMP	DOFDOF3:	LOAD	A,RANG	COMP	A,#1	JUMP,EQ	DOF3B	COMP	A,#2	JUMP,EQ	DOF3CDOF3A:	LOAD	A,#1	LOAD	RANGS,A	LOAD	IX,#TXRAP	CALL	AFTEXT	LOAD	A,NBRAP	JUMP	DOFF3DOF3B:	LOAD	A,#2	LOAD	RANGS,A	LOAD	IX,#TXEAP	CALL	AFTEXT	LOAD	A,NBEAP	JUMP	DOFF3DOF3C:	LOAD	A,#0	LOAD	RANGS,A	LOAD	IX,#TXSAP	CALL	AFTEXT	LOAD	A,NBSAPDOFF3:	CALL	AFDEC20$:	CALL	GETCAR		; attend une touche ...	COMP	A,#F1	JUMP,EQ	DOFF	COMP	A,#F2	JUMP,EQ	DOFF	COMP	A,#F3	JUMP,EQ	DOFF	COMP	A,#ENTER	JUMP,EQ	DOFF	JUMP	20$DOF:	CALL	GETLINE		; attend une ligne ...DOFF:	COMP	A,#ENTER	JUMP,EQ 50$	COMP	A,FONC	JUMP,EQ 20$	LOAD	FONC,A	JUMP	LOOP020$:	LOAD	A,RANGS	LOAD	RANG,A	JUMP	LOOP50$:	JUMP	SURVEILLETXTEL:	.ASCIZ	"No tel: "TXCOD0:	.ASCIZ	"Appels: [TOUS]  "TXCOD1:	.ASCIZ	"Appels: [CODE 2]"TXDEL1:	.ASCIZ	"Duree appel: "TXDEL2:	.ASCIZ	"Duree cris: "TXDEL3:	.ASCIZ	"Frequence: "TXRAP:	.ASCIZ	"Appels recus: "TXEAP:	.ASCIZ	"Appels faux:  "TXSAP:	.ASCIZ	"Appels faits: "SURVEILLE:	LOAD	A,BUTEL	COMP	A,#0		; numro existe ?	JUMP,NE 05$		; oui => 05$				; non =>	CALL	AFEOP	LOAD	IX,#TXS5	CALL	AFTEXT		; affiche numro inconnu	LOAD	A,#100*2	CALL	WAITMS		; attend 2s	LOAD	A,#F1	LOAD	FONC,A	JUMP	LOOP005$:	CALL	AFEOP	LOAD	IX,#TXS1	CALL	AFTEXT	LOAD	A,#H'20	LOAD	MARQUE,A	LOAD	IX,#110$:	DEC	IX	JUMP,NE 15$	LOAD	IX,#2000	; IX <-- frquence de clignotement	LOAD	A,#15	CALL	SETCURS		; met le curseur tout  droite	LOAD	A,MARQUE	CALL	AFCAR		; affiche la marque	LOAD	B,#H'20		; B <-- blanc	COMP	A,#H'20	JUMP,NE 13$	LOAD	B,#H'7F		; B <-- flche "<-"13$:	LOAD	MARQUE,B15$:	CALL	CRI?		; un cri ?	JUMP,CS 20$	CALL	SONNE?		; quelqu'un sonne ?	JUMP,CS 40$	CALL	IFCAR		; une touche appuye ?	COMP	A,#ENTER	JUMP,NE 10$	JUMP	LOOP20$:				; on a cri =>	CALL	AFEOP	LOAD	IX,#TXS2	CALL	AFTEXT	LOAD	A,NBSAP	INC	A		; NBSAP <-- un appel fait de plus	LOAD	NBSAP,A	CALL	APPEL		; appelle le numro choisi ...	JUMP	60$38$:	JUMP	SURVEILLE40$:				; on a sonn =>	CALL	AFEOP	LOAD	IX,#TXS3	CALL	AFTEXT	LOAD	B,#10*6		; B <-- 6 secondes42$:	LOAD	A,#10	CALL	WAITMS		; attend 0.1s ...	DEC	B	JUMP,EQ 38$	CALL	SONNE?		; deuxime coup de sonnerie ?	JUMP,CC 42$		; non => 42$	LOAD	A,CODE		; appels cods ?	JUMP,EQ 46$		; non => 46$				; oui =>	LOAD	B,#10*25	; B <-- 25 secondes44$:	LOAD	A,#10	CALL	WAITMS		; attend 0.1s ...	DEC	B	JUMP,EQ 38$	CALL	SONNE?		; troisime coup de sonnerie ?	JUMP,CC 44$		; non => 44$	COMP	B,#10*(25-6)	; troisime coup  la suite ?	JUMP,HS 90$		; oui => 90$ (dsol, mais y'a un code)46$:	LOAD	A,NBRAP	INC	A		; NBSAP <-- un appel reu de plus	LOAD	NBRAP,A	CALL	DECROCHE	; dcroche la cornette60$:	CALL	AFEOP	LOAD	IX,#TXS4	CALL	AFTEXT	LOAD	IX,#TMU1	CALL	MUSIQUE		; musique de dbut ...	LOAD	IX,#BUDEL1	CALL	GETNUM		; A <-- nombre dans BUDEL1	LOAD	B,A		; B <-- nb de secondes65$:	LOAD	A,#100	CALL	WAITMS		; attend 1s ...	DEC	B	JUMP,EQ 68$	CALL	IFCAR	COMP	A,#F1	JUMP,NE 65$68$:	LOAD	IX,#TMU2	CALL	MUSIQUE		; musique de fin ...	CALL	RACCROCHE	; racroche la cornette	JUMP	SURVEILLE90$:	LOAD	A,NBEAP	INC	A		; NBEAP <-- un appel reu sans code de plus	LOAD	NBEAP,A	CALL	AFEOP	LOAD	IX,#TXS6	CALL	AFTEXT92$:	LOAD	B,#10*6		; B <-- 6 secondes94$:	LOAD	A,#10	CALL	WAITMS		; attend 0.1s ...	DEC	B	JUMP,EQ 96$	CALL	SONNE?		; encore un coup de sonnerie ?	JUMP,CC 94$		; non => 94$	JUMP	92$		; oui => 92$96$:	JUMP	SURVEILLETXS1:	.ASCIZ	"Je surveille..."TXS2:	.ASCIZ	"On a crie !"TXS3:	.ASCIZ	"Quelqu'un sonne"TXS4:	.ASCIZ	"[F1] = raccroche"TXS5:	.ASCIZ	"No tel inconnu !"TXS6:	.ASCIZ	"Appel sans code!"; Appels systme volus; ----------------------;--------\\; APPEL   >;========/; Appel le numro dans BUTEL.; in	-; out	-; mod	F,A,B,IXAPPEL:	CALL	AFEOP		; efface tout	LOAD	IX,#00$	CALL	AFTEXT	CALL	DECROCHE	; dcroche la cornette	LOAD	IX,#BUTEL20$:	LOAD	A,(IX)	INC	IX	COMP	A,#'0	JUMP,LO 25$	COMP	A,#'9	JUMP,HI 25$	CALL	AFCAR		; affiche le chiffre	SUB	A,#'0		; A <-- 0..9	CALL	COMPOSE		; compose un chiffre	JUMP	20$25$:90$:	RET00$:	.ASCIZ	"Fait le ";--------\\; GETLINE >;========/; Attend une ligne de chiffres.; in	IX	^buffer;	B	lg max du buffer; out	A	dernire touche; mod	F,AGETLINE:	PUSH	B	PUSH	IX	LOAD	A,CPOS	LOAD	SAVPOS,A	; SAVPOS <-- position du curseur	LOAD	SAVLGB,B	; SAVLGB <-- lg max buffer	LOAD	SAVPTB,IX	; SAVPTB <-- ^buffer	CALL	AFTEXT		; affiche le chiffre actuel	LOAD	A,SAVPOS;;?	DEC	A		; A <-- curseur juste devant	CALL	SETCURS	LOAD	IX,SAVPTB10$:	CALL	GETCAR		; A <-- attend une touche	COMP	A,#CLEAR	JUMP,EQ 50$	COMP	A,#'0	JUMP,LO 90$	COMP	A,#'9	JUMP,HI 90$				; 0..9 =>	COMP	B,#0	JUMP,EQ 10$	DEC	B	LOAD	(IX),A		; buffer <-- chiffre	INC	IX	LOAD	A,#0	LOAD	(IX),A	CALL	AFFLINE		; affiche toute la ligne	JUMP	10$50$:				; CLEAR =>	LOAD	IX,SAVPTB	LOAD	B,SAVLGB	LOAD	A,#0	LOAD	(IX),A	CALL	AFFLINE		; affiche toute la ligne	JUMP	10$90$:	POP	IX	POP	B	RET;--------\\; AFFLINE >;--------/; Pour GETLINE: Affiche toute la ligne.; in	-; out	-; mod	FAFFLINE:	PUSH	A	PUSH	B	PUSH	IX	LOAD	A,SAVPOS	CALL	SETCURS		; remet le curseur au dbut	LOAD	IX,SAVPTB	LOAD	B,SAVLGB20$:	LOAD	A,(IX)	INC	IX	COMP	A,#0		; fin du texte ?	JUMP,EQ 40$		; oui => 40$	CALL	AFCAR		; affiche un caractre	DEC	B	JUMP,NE 20$	JUMP	90$40$:	LOAD	A,CPOS	PUSH	A50$:	LOAD	A,#' 	CALL	AFCAR		; efface la fin de la ligne	DEC	B	JUMP,NE 50$	POP	A	CALL	SETCURS90$:	POP	IX	POP	B	POP	A	RET;--------\\; GETNUM  >;========/; in	IX	^nombre en ASCII; out	A	nombre; mod	F,A,IXGETNUM:	PUSH	B	LOAD	A,#0		; A <-- futur nombre10$:	LOAD	B,(IX)	COMP	B,#'0	JUMP,LO 90$	COMP	B,#'9	JUMP,HI 90$	SLC	A	LOAD	B,A	SLC	A	SLC	A	ADD	A,B		; A <-- A *10	LOAD	B,(IX)	SUB	B,#'0	ADD	A,B		; A <-- nouveau digit	INC	IX	JUMP	10$90$:	POP	B	RET; Gestion de l'affichage; ----------------------;--------\\; AFEOP   >;========/; Efface tout le LCD.; in	-; out	-; mod	F,AAFEOP:	LOAD	A,#0	LOAD	CPOS,A	LOAD	A,#B'00000001	; A <-- efface tout	CALL	AFCOMM	LOAD	A,#1640/10	; A <-- 1.64ms	JUMP	WAITUS;--------\\; AFDEC   >;========/; Affiche un nombre dcimal compris entre 0 et 99.; Avec un peu plus de temps, on peut surement crire; beaucoup mieux cette routine !; in	A	nombre; out	-; mod	F,AAFDEC:	PUSH	B	LOAD	B,A	COMP	A,#90	JUMP,HS 90$	COMP	A,#80	JUMP,HS 80$	COMP	A,#70	JUMP,HS 70$	COMP	A,#60	JUMP,HS 60$	COMP	A,#50	JUMP,HS 50$	COMP	A,#40	JUMP,HS 40$	COMP	A,#30	JUMP,HS 30$	COMP	A,#20	JUMP,HS 20$	COMP	A,#10	JUMP,LO 95$10$:	LOAD	A,#'1	CALL	AFCAR	SUB	B,#10	JUMP	95$20$:	LOAD	A,#'2	CALL	AFCAR	SUB	B,#20	JUMP	95$30$:	LOAD	A,#'3	CALL	AFCAR	SUB	B,#30	JUMP	95$40$:	LOAD	A,#'4	CALL	AFCAR	SUB	B,#40	JUMP	95$50$:	LOAD	A,#'5	CALL	AFCAR	SUB	B,#50	JUMP	95$60$:	LOAD	A,#'6	CALL	AFCAR	SUB	B,#60	JUMP	95$70$:	LOAD	A,#'7	CALL	AFCAR	SUB	B,#70	JUMP	95$80$:	LOAD	A,#'8	CALL	AFCAR	SUB	B,#80	JUMP	95$90$:	LOAD	A,#'9	CALL	AFCAR	SUB	B,#90;	JUMP	95$95$:	LOAD	A,B	ADD	A,#'0	CALL	AFCAR	POP	B	RET;--------\\; AFTEXT  >;========/; Affiche un texte termin par zro.; in	IX	^texte; out	IX	^plus loin; mod	F,A,IXAFTEXT:10$:	LOAD	A,(IX)	JUMP,EQ 90$	CALL	AFCAR		; affiche un caractre	INC	IX	JUMP	10$90$:	RET;--------\\; AFCAR   >;========/; Affiche un caractre sur le LCD.; in	A	caractre  afficher; out	-; mod	FAFCAR:	PUSH	A	PUSH	B	LOAD	B,A	PUSH	B	AND	B,#B'11110000	LOAD	A,DATA3	AND	A,#B'00001111	OR	A,#B'00001100	ADD	A,B	LOAD	DATA3,A	CALL	LCDPULSE	POP	B	RLC	B	RLC	B	RLC	B	RLC	B	AND	B,#B'11110000	AND	A,#B'00001111	OR	A,#B'00001100	ADD	A,B	LOAD	DATA3,A	CALL	LCDPULSE	LOAD	A,#40/10	; A <-- 40us	CALL	WAITUS	INC	CPOS	POP	B	POP	A	RET;--------\\; SETCURS >;========/; Positionne le curseur.; in	A	position (0..15); out	-; mod	F,ASETCURS:	LOAD	CPOS,A	OR	A,#B'10000000	; A <-- set DD RAM	JUMP	AFCOMM;--------\\; LCDINIT >;--------/; Reset le LCD. Il faut respecter tout un protocole pas; vraiment clair (voir manuel HITACHI) !; in	-; out	-; mod	F,ALCDINIT:	LOAD	A,#B'00110000	; A <-- fonction 8 bits	CALL	AFCOMM4	LOAD	A,#1		; A <-- 10ms	CALL	WAITMS	LOAD	A,#B'00110000	; A <-- fonction 8 bits	CALL	AFCOMM4	LOAD	A,#100/10	; A <-- 100us	CALL	WAITUS	LOAD	A,#B'00100000	; A <-- fonction 4 bits	CALL	AFCOMM4	LOAD	A,#B'00100000	; A <-- fonction 1 ligne et 5x7	CALL	AFCOMM	LOAD	A,#B'00001110	; A <-- display ON, cursor ON et blink OFF	CALL	AFCOMM	LOAD	A,#B'00000001	; A <-- efface tout	CALL	AFCOMM	LOAD	A,#1640/10	; A <-- 1.64ms	CALL	WAITUS	LOAD	A,#B'00000110	; A <-- mode d'entre incrmental	CALL	AFCOMM	LOAD	A,#0	LOAD	CPOS,A	RET;--------\\; AFCOMM  >;========/; Envoie une commande 8 bits au LCD.; in	A	commande; out	-; mod	FAFCOMM:	PUSH	A	PUSH	B	LOAD	B,A	PUSH	B	AND	B,#B'11110000	LOAD	A,DATA3	AND	A,#B'00000111	OR	A,#B'00000100	ADD	A,B	LOAD	DATA3,A	CALL	LCDPULSE	POP	B	RLC	B	RLC	B	RLC	B	RLC	B	AND	B,#B'11110000	AND	A,#B'00000111	OR	A,#B'00000100	ADD	A,B	LOAD	DATA3,A	CALL	LCDPULSE	LOAD	A,#40/10	; A <-- 40us	CALL	WAITUS	POP	B	POP	A	RET;--------\\; AFCOMM4 >;========/; Envoie une commande 4 bits au LCD.; in	A	commande; out	-; mod	FAFCOMM4:	PUSH	A	PUSH	B	LOAD	B,A	AND	B,#B'11110000	LOAD	A,DATA3	AND	A,#B'00000111	OR	A,#B'00000100	ADD	A,B	LOAD	DATA3,A	CALL	LCDPULSE	LOAD	A,#40/10	; A <-- 40us	CALL	WAITUS	POP	B	POP	A	RET;---------\\; LCDPULSE >;---------/; Effectue une pulse sur la ligne E du LCD d'au moins 450ns.; in	-; out	-; mod	FLCDPULSE:	PUSH	A	LOAD	A,DATA3	AND	A,#B'11111011	LOAD	DATA3,A		; flanc descendant	OR	A,#B'00000100	LOAD	DATA3,A		; flanc montant	POP	A	RET; Gestion du clavier; ------------------;--------\\; GETCAR  >;========/; Attend une touche du clavier.; in	-; out	A	touche presse; mod	F,AGETCAR:	PUSH	B10$:	CALL	BALCLA		; A <-- touche presse	COMP	A,#0		; une touche presse ?	JUMP,EQ 10$		; non => 10$	LOAD	B,A		; B <-- touche presse20$:	CALL	BALCLA		; A <-- touche presse	COMP	A,#0		; une touche presse ?	JUMP,NE 20$		; oui => 20$	LOAD	A,B		; A <-- touche presse	POP	B	RET;--------\\; IFCAR   >;========/; Regarde si une touche du clavier est presse.; in	-; out	A	touche presse; mod	F,AIFCAR:	PUSH	B	CALL	BALCLA		; A <-- touche presse	COMP	A,#0		; une touche presse ?	JUMP,EQ 90$		; non => 90$	LOAD	B,A		; B <-- touche presse20$:	CALL	BALCLA		; A <-- touche presse	COMP	A,#0		; une touche presse ?	JUMP,NE 20$		; oui => 20$	LOAD	A,B		; A <-- touche presse90$:	POP	B	RET;--------\\; BALCLA  >;--------/; Balaye le clavier pour trouver la premire touche presse.; in	-; out	A	touche presse; mod	F,ABALCLA:	PUSH	B	PUSH	IX	LOAD	IX,#TAKEY	; IX <-- ^table des touches	LOAD	B,#H'FE10$:	LOAD	DATA4,B		; slectionne une colonne	NOP	LOAD	A,DATA4		; A <-- lit une ligne	RLC	A	JUMP,CC	80$	INC	IX	RLC	A	JUMP,CC	80$	INC	IX	RLC	A	JUMP,CC	80$	INC	IX	RLC	A	JUMP,CC	80$	INC	IX	SETC	RLC	B		; B <-- colonne suivante	COMP	B,#H'EF	JUMP,NE 10$	LOAD	A,#0		; A <-- aucune touche presse	JUMP	90$80$:	LOAD	A,(IX)		; A <-- touche presse90$:	LOAD	B,#H'FF	LOAD	DATA4,B	POP	IX	POP	B	RET; Tables des touches du clavier; ----------------------------TAKEY:	.B	0	'1	'4	'7	; colonne 1	.B	'0	'2	'5	'8	; colonne 2	.B	ENTER	F1	F2	F3	; colonne 3	.B	CLEAR	'3	'6	'9	; colonne 4; Dtection d'vnements extrieurs; ---------------------------------;--------\\; CRI?    >;--------/; Regarde si quelqu'un crie (dans le micro).; in	-; out	CC	pas de cri;	CS	on a cri; mod	F,ACRI?:	PUSH	IX	LOAD	A,DATA1	AND	A,#B'00000010	JUMP,NE 90$	LOAD	IX,#0 	LOAD	COUNT1,IX10$:	LOAD	IX,COUNT1	INC	IX		; COUNT1 <-- temps o signal = 1	LOAD	COUNT1,IX	LOAD	A,DATA1	AND	A,#B'00000010	JUMP,EQ 10$	LOAD	IX,#2000	LOAD	COUNT0,IX15$:	LOAD	IX,COUNT0	DEC	IX	LOAD	COUNT0,IX	JUMP,EQ 20$	LOAD	A,DATA1	AND	A,#B'00000010	JUMP,NE 15$	JUMP	10$20$:	LOAD	IX,#100	COMP	IX,COUNT1	JUMP,HS 90$80$:	POP	IX	SETC			; CS => on a sonn	RET90$:	POP	IX	CLRC			; CC => pas de sonnerie	RET;--------\\; SONNE?  >;--------/; Regarde si quelqu'un sonne.; in	-; out	CC	pas de sonnerie;	CS	on a sonn; mod	F,ASONNE?:	PUSH	IX	LOAD	A,DATA1	AND	A,#B'00000001	JUMP,NE 90$	LOAD	IX,#0 	LOAD	COUNT1,IX10$:	LOAD	IX,COUNT1	INC	IX		; COUNT1 <-- temps o signal = 1	LOAD	COUNT1,IX	LOAD	A,DATA1	AND	A,#B'00000001	JUMP,EQ 10$	LOAD	IX,#1000	LOAD	COUNT0,IX15$:	LOAD	IX,COUNT1	INC	IX		; COUNT1 <-- temps o signal = 1	LOAD	COUNT1,IX	LOAD	IX,COUNT0	DEC	IX	LOAD	COUNT0,IX	JUMP,EQ 20$	LOAD	A,DATA1	AND	A,#B'00000001	JUMP,NE 15$	JUMP	10$20$:	LOAD	IX,#10000	COMP	IX,COUNT1	JUMP,HS 90$80$:	POP	IX	SETC			; CS => on a sonn	RET90$:	POP	IX	CLRC			; CC => pas de sonnerie	RET; Emission de bips; ----------------;--------\\; MUSIQUE >;========/; in	IX	^tyble musique; out	-; mod	F,A,IXMUSIQUE:10$:	LOAD	A,(IX)		; A <-- une note	INC	IX	COMP	A,#0		; fin de la table ?	JUMP,EQ 90$		; oui => 90$	CALL	BIP	JUMP	10$90$:	RET;--------\\; BIP     >;========/; in	A	note; out	-; mod	F,ABIP:	PUSH	B	LOAD	NOTE,A	LOAD	B,#10010$:	LOAD	A,NOTE	CALL	WAITUS		; attend ...	LOAD	A,DATA1	OR	A,#B'00000100	LOAD	DATA1,A	LOAD	A,NOTE	CALL	WAITUS		; attend ...	LOAD	A,DATA1	AND	A,#B'11111011	LOAD	DATA1,A	DEC	B	JUMP,NE 10$	POP	B	RETTMU1:	.B	DO,MI,SOL,DO1,DO1,DO,MI,SOL,DO1,DO1,0TMU2:	.B	DO1,SOL,MI,DO,DO,DO1,SOL,MI,DO,DO,0; Composition de numros; ----------------------;---------\\; DECROCHE >;=========/; Dcroche la cornette.; in	-; out	-; mod	F,ADECROCHE:	LOAD	A,DATA3	OR	A,#B'00000001	; A <-- tire le relai "f"	LOAD	DATA3,A	LOAD	A,#100*2	CALL	WAITMS		; attend 2s	RET;----------\\; RACCROCHE >;==========/; Repose la cornette.; in	-; out	-; mod	F,ARACCROCHE:	LOAD	A,DATA3	AND	A,#B'11111110	; A <-- relche le relai "f"	LOAD	DATA3,A	RET;--------\\; COMPOSE >;========/; Compose juste un chiffre.; in	A	numro (0..9); out	-; mod	F,ACOMPOSE:	PUSH	B	COMP	A,#0	JUMP,NE 10$	LOAD	A,#10		; A <-- 10 impulsions pour un zro10$:	LOAD	B,A20$:	LOAD	A,DATA3	OR	A,#B'00000010	; A <-- tire le relai "i"	LOAD	DATA3,A	LOAD	A,#6	CALL	WAITMS		; attend 60ms	LOAD	A,DATA3	AND	A,#B'11111101	; A <-- relche le relai "i"	LOAD	DATA3,A	LOAD	A,#4	CALL	WAITMS		; attend 40ms	DEC	B	JUMP,NE 20$	LOAD	A,#60	CALL	WAITMS		; attend 600ms	POP	B	RET;--------\\; WAITMS  >;--------/; Attend un peu ...; in	A	attente (unit: 10ms); out	-; mod	F,AWAITMS:	PUSH	IX10$:	LOAD	IX,#10000/4	; IX <-- 10ms/4us20$:	DEC	IX		;  1 cycle	JUMP,NE 20$		;  3 cycles				; ---	DEC	A		;  4 cycles au total	JUMP,NE 10$	POP	IX	RET;--------\\; WAITUS  >;--------/; Attend un peu ...; in	A	attente (unit: 10us); out	-; mod	F,AWAITUS:10$:	NOP			;  1 cycle	NOP			;  1 cycle	NOP			;  1 cycle	NOP			;  1 cycle	NOP			;  1 cycle	NOP			;  1 cycle	NOP			;  1 cycle	DEC	A		;  3 cycles	JUMP,NE	10$		; ---	RET			; 10 cycles au total; REMARQUE:	1 cycle du processeur dure 1us !; Initialisation; --------------;--------\\; INIPER  >;========/; in	IX	^table; out	-; mod	F,A,B,IXINIPER:10$:	LOAD	B,(IX)+0	; B <-- adresse	COMP	B,#-1	JUMP,EQ 90$	LOAD	A,(IX)+1	; A <-- data	PUSH	IX	LOAD	IX,#REG	ADD	IX,B		; IX <-- adresse	LOAD	(IX),A		; (adresse) <-- data	POP	IX	INC	IX	INC	IX	JUMP	10$90$:	RET; Dans le deuxime byte: 0=input 1=outputTAINIT:	.B	DDIR1,B'00000100	; dtecteurs	.B	DDIR2,B'00000000	.B	DDIR3,B'11111111	; LCD + relais	.B	DDIR4,B'00001111	; clavier	.B	DATA3,B'11111100	; tout le LCD  1 et relais relchs	.B	-1			; fin de la table; Vecteurs  la fin de la mmoire; -------------------------------	.LOC	ROM+LROM-H'10	.W	START		; SCI	.W	START		; TOF	.W	START		; OCF	.W	START		; ICF	.W	START		; IRQ	.W	START		; SWI	.W	START		; NMI	.W	START		; RESET	.END	START